#include <stdio.h>
#include <stdint.h>

static inline long long maxXorSum(long long N) {
    long long ans = 0;
    while (N > 1) {
        int k = 63 - __builtin_clzll(N); // floor(log2 N)
        long long low = 1LL << k;
        long long high = (1LL << (k + 1)) - 1;
        long long cnt = N - low + 1; // numbers in [low, N]
        if (N == high) cnt--; // cannot use the number 'high' itself
        ans += 2LL * cnt * high;
        N = low - cnt - 1; // remaining numbers
    }
    return ans; // N is 0 or 1 -> contribution 0
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        long long N; scanf("%lld", &N);
        printf("%lld\n", maxXorSum(N));
    }
    return 0;
}

