#include <bits/stdc++.h>
using namespace std;

using int64 = long long;

int64 solve(int64 N) {
    int64 ans = 0;
    while (N > 1) {
        int k = 63 - __builtin_clzll(N); // floor(log2 N)
        int64 low = 1LL << k;
        int64 high = (1LL << (k + 1)) - 1;
        int64 cnt = N - low + 1; // size of upper part
        if (N == high) cnt--; // exclude the element that would map to 0
        ans += 2LL * cnt * high;
        N = low - cnt - 1; // remaining numbers
    }
    return ans; // N==0 or 1 gives 0
}

