import java.io.*;
import java.util.*;

public class Main {
    private static long maxXorSum(long N) {
        long ans = 0;
        while (N > 1) {
            int k = 63 - Long.numberOfLeadingZeros(N); // floor(log2 N)
            long low = 1L << k;
            long high = (1L << (k + 1)) - 1;
            long cnt = N - low + 1; // numbers in upper part
            if (N == high) cnt--; // cannot pair with 0
            ans += 2L * cnt * high;
            N = low - cnt - 1; // remaining numbers
        }
        return ans; // N==0 or 1 contributes 0
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sb = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int t = 0; t < T; t++) {
            long N = Long.parseLong(br.readLine().trim());
            sb.append(maxXorSum(N)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

