const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let out = [];
function maxXorSum(N) {
  let ans = 0n;
  let n = BigInt(N);
  while (n > 1n) {
    const k = n.toString(2).length - 1; // floor(log2 n)
    const low = 1n << BigInt(k);
    const high = (1n << BigInt(k + 1)) - 1n;
    let cnt = n - low + 1n;
    if (n === high) cnt -= 1n;
    ans += 2n * cnt * high;
    n = low - cnt - 1n;
  }
  return ans.toString();
}
for (let t = 0; t < T; ++t) {
  const N = Number(input[idx++]);
  out.push(maxXorSum(N));
}
